// Process YoY Data (API version) - outputs a YoY table pack with optional org-program split

const LOCALE = "en-GB";
const SUPPORTED_CURRENCIES = new Set(["GBP", "EUR", "USD", "AUD", "SEK", "NOK", "DKK", "ISK", "PLN"]);
const PROGRAM_TABLE_LIMIT = 6;

function normalizeCurrencyCode(code) {
  const c = String(code || "").trim().toUpperCase();
  return SUPPORTED_CURRENCIES.has(c) ? c : "";
}

function safeNum(x) {
  if (x === null || x === undefined || x === "") return 0;
  if (typeof x === "number") return Number.isFinite(x) ? x : 0;

  let s = String(x).trim().replace(/[^\d,.-]/g, "").replace(/\s+/g, "");
  if (!s) return 0;

  const lastComma = s.lastIndexOf(",");
  const lastDot = s.lastIndexOf(".");

  if (lastComma > -1 && lastDot > -1) {
    if (lastComma > lastDot) {
      s = s.replace(/\./g, "");
      const i = s.lastIndexOf(",");
      s = s.slice(0, i).replace(/,/g, "") + "." + s.slice(i + 1);
    } else {
      s = s.replace(/,/g, "");
    }
  } else if (lastComma > -1) {
    const decDigits = s.length - lastComma - 1;
    if (decDigits >= 1 && decDigits <= 2) {
      s = s.slice(0, lastComma).replace(/,/g, "") + "." + s.slice(lastComma + 1);
    } else {
      s = s.replace(/,/g, "");
    }
  } else if (lastDot > -1) {
    const decDigits = s.length - lastDot - 1;
    if (!(decDigits >= 1 && decDigits <= 2)) s = s.replace(/\./g, "");
  }

  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

function pct(a, b) {
  if (!b) return null;
  return (a / b) * 100;
}

function varPct(a, b) {
  return b ? ((a - b) / b) * 100 : null;
}

function getCurrencySymbol(code) {
  switch (String(code || "").toUpperCase()) {
    case "GBP": return "\u00A3";
    case "EUR": return "\u20AC";
    case "USD": return "$";
    case "AUD": return "A$";
    case "PLN": return "z\u0142";
    case "SEK":
    case "NOK":
    case "DKK":
    case "ISK": return "kr";
    default: return "";
  }
}

function fmtInt(x) {
  return Math.round(safeNum(x)).toLocaleString(LOCALE);
}

function fmtMoney0(x, sym) {
  const n = Math.round(safeNum(x));
  const sign = n < 0 ? "-" : "";
  return `${sign}${sym}${Math.abs(n).toLocaleString(LOCALE)}`;
}

function fmtMoney2(x, sym) {
  const n = safeNum(x);
  const sign = n < 0 ? "-" : "";
  return `${sign}${sym}${Math.abs(n).toLocaleString(LOCALE, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
}

function fmtPct2(x) {
  if (x === null || x === undefined || Number.isNaN(x)) return "";
  return `${Number(x).toFixed(2)}%`;
}

function fmtVar1(x) {
  if (x === null || x === undefined || Number.isNaN(x)) return "N/A";
  const v = Number(x);
  return `${v >= 0 ? "+" : ""}${v.toFixed(1)}%`;
}

function aggregate(items) {
  return (items || []).reduce((acc, item) => {
    const commission = item.commission || item.salesCommission || {};
    acc.clicks += safeNum(item.clicks);
    acc.sales += safeNum(item.sales);
    acc.orderValue += safeNum(item.orderValue ?? item.salesOrderValue);
    acc.pubCommission += safeNum(commission.publisherCommission);
    acc.totalCommission += safeNum(commission.totalCommission);
    return acc;
  }, { clicks: 0, sales: 0, orderValue: 0, pubCommission: 0, totalCommission: 0 });
}

function calc(agg) {
  const clicks = agg.clicks;
  const sales = agg.sales;
  const orderValue = agg.orderValue;
  const aov = sales ? (orderValue / sales) : 0;
  const pubCommission = agg.pubCommission;
  const totalCommission = agg.totalCommission;
  const convRate = clicks ? pct(sales, clicks) : 0;
  const cpa = sales ? (totalCommission / sales) : 0;
  const roi = totalCommission ? (orderValue / totalCommission) : 0;

  return {
    clicks,
    sales,
    convRate,
    orderValue,
    aov,
    pubCommission,
    totalCommission,
    cpa,
    roi
  };
}

function pickProgramIdentity(item) {
  const rawId = item.programId ?? item.id ?? item.program?.id ?? item.programID ?? "";
  const id = String(rawId || "").trim();
  const name = [
    item.programName,
    item.name,
    item.program?.name,
    item.programDisplayName,
    item.programTitle
  ]
    .map((value) => String(value || "").trim())
    .find(Boolean) || (id ? `Program ${id}` : "Unknown program");

  const market = [
    item.market,
    item.marketName,
    item.country,
    item.countryCode,
    item.region
  ]
    .map((value) => String(value || "").trim())
    .find(Boolean) || "-";

  return {
    key: id || name.toLowerCase(),
    id: id || "-",
    name,
    market
  };
}

function aggregateByProgram(items) {
  const map = new Map();

  for (const item of items || []) {
    const identity = pickProgramIdentity(item);
    const key = identity.key;
    const commission = item.commission || item.salesCommission || {};

    if (!map.has(key)) {
      map.set(key, {
        key,
        programId: identity.id,
        programName: identity.name,
        market: identity.market,
        clicks: 0,
        impressions: 0,
        sales: 0,
        orderValue: 0,
        totalCommission: 0
      });
    }

    const acc = map.get(key);
    acc.clicks += safeNum(item.clicks);
    acc.impressions += safeNum(item.impressions);
    acc.sales += safeNum(item.sales);
    acc.orderValue += safeNum(item.orderValue ?? item.salesOrderValue);
    acc.totalCommission += safeNum(commission.totalCommission);
  }

  return Array.from(map.values());
}

const allCurrentItems = $node["Collect Page (API 2025)"].json.allItems || [];
const allPreviousItems = $node["Collect Page (API 2024)"].json.allItems || [];
const payload = $node["yoy data extraction1"]?.json?.payload || {};

const analysisLevelForFiltering = String(payload.analysisLevel || "program").toLowerCase();

function toTrimmedStringSet(values) {
  return new Set((values || []).map((value) => String(value || "").trim()).filter(Boolean));
}

function toLowerStringSet(values) {
  return new Set((values || []).map((value) => String(value || "").trim().toLowerCase()).filter(Boolean));
}

const selectedProgramIds = toTrimmedStringSet([
  payload.programId,
  payload.publisherProgramId,
  ...(Array.isArray(payload.programIds) ? payload.programIds : []),
  ...(Array.isArray(payload.publisherProgramIds) ? payload.publisherProgramIds : [])
]);

const selectedProgramNames = toLowerStringSet([
  payload.programName,
  payload.clientName,
  payload.publisherProgramName
]);

function filterBySelection(items) {
  return (items || []).filter((item) => {
    const rowProgramId = String(item.programId ?? item.id ?? item.program?.id ?? "").trim();
    const rowProgramName = String(
      item.programName ?? item.name ?? item.program?.name ?? item.programDisplayName ?? ""
    ).trim().toLowerCase();

    const idMatch = rowProgramId && selectedProgramIds.has(rowProgramId);
    const nameMatch = rowProgramName && selectedProgramNames.has(rowProgramName);

    return idMatch || nameMatch;
  });
}

let currentItems = allCurrentItems;
let previousItems = allPreviousItems;

let currentFilterMatched = false;
let previousFilterMatched = false;

if (analysisLevelForFiltering === "program" && (selectedProgramIds.size > 0 || selectedProgramNames.size > 0)) {
  const filteredCurrent = filterBySelection(allCurrentItems);
  const filteredPrevious = filterBySelection(allPreviousItems);

  // Fallback independently by period. Some historical stats rows may not carry the same
  // program identifiers as current rows; do not zero the prior-year baseline when that happens.
  if (filteredCurrent.length > 0) {
    currentItems = filteredCurrent;
    currentFilterMatched = true;
  }
  if (filteredPrevious.length > 0) {
    previousItems = filteredPrevious;
    previousFilterMatched = true;
  }
}

const selectedCurrencyCode = normalizeCurrencyCode(payload.currencyCode || $json?.payload?.currencyCode);
const apiCurrencyCode = normalizeCurrencyCode(currentItems[0]?.reportCurrencyCode || previousItems[0]?.reportCurrencyCode);
const currencyCode = selectedCurrencyCode || apiCurrencyCode || "EUR";
const currencySymbol = getCurrencySymbol(currencyCode);
const reportingPeriod = payload.reportingPeriod || "";
const comparisonPeriod = payload.comparisonPeriod || "";
const analysisLevel = String(payload.analysisLevel || "program").toLowerCase();

const curAgg = aggregate(currentItems);
const prevAgg = aggregate(previousItems);
const previousBaselineAvailable = previousItems.some((item) => {
  return safeNum(item.clicks) > 0 || safeNum(item.sales) > 0 || safeNum(item.orderValue ?? item.salesOrderValue) > 0;
});
const cur = calc(curAgg);
const prev = calc(prevAgg);

function diff(a, b) { return a - b; }

const rows = [
  {
    Row: "Recent",
    Clicks: fmtInt(cur.clicks),
    Sales: fmtInt(cur.sales),
    "Conv Rate": fmtPct2(cur.convRate),
    "Order value": fmtMoney0(cur.orderValue, currencySymbol),
    AOV: fmtMoney2(cur.aov, currencySymbol),
    "Publ Commission": fmtMoney0(cur.pubCommission, currencySymbol),
    "Total Commission": fmtMoney0(cur.totalCommission, currencySymbol),
    CPA: fmtMoney2(cur.cpa, currencySymbol),
    ROI: cur.roi ? cur.roi.toFixed(2) : ""
  },
  {
    Row: "Previous",
    Clicks: fmtInt(prev.clicks),
    Sales: fmtInt(prev.sales),
    "Conv Rate": fmtPct2(prev.convRate),
    "Order value": fmtMoney0(prev.orderValue, currencySymbol),
    AOV: fmtMoney2(prev.aov, currencySymbol),
    "Publ Commission": fmtMoney0(prev.pubCommission, currencySymbol),
    "Total Commission": fmtMoney0(prev.totalCommission, currencySymbol),
    CPA: fmtMoney2(prev.cpa, currencySymbol),
    ROI: prev.roi ? prev.roi.toFixed(2) : ""
  },
  {
    Row: "Difference",
    Clicks: fmtInt(diff(cur.clicks, prev.clicks)),
    Sales: fmtInt(diff(cur.sales, prev.sales)),
    "Conv Rate": fmtPct2(diff(cur.convRate, prev.convRate)),
    "Order value": fmtMoney0(diff(cur.orderValue, prev.orderValue), currencySymbol),
    AOV: fmtMoney2(diff(cur.aov, prev.aov), currencySymbol),
    "Publ Commission": fmtMoney0(diff(cur.pubCommission, prev.pubCommission), currencySymbol),
    "Total Commission": fmtMoney0(diff(cur.totalCommission, prev.totalCommission), currencySymbol),
    CPA: fmtMoney2(diff(cur.cpa, prev.cpa), currencySymbol),
    ROI: diff(cur.roi, prev.roi).toFixed(2)
  },
  {
    Row: "% Variance",
    Clicks: fmtVar1(varPct(cur.clicks, prev.clicks)),
    Sales: fmtVar1(varPct(cur.sales, prev.sales)),
    "Conv Rate": fmtVar1(varPct(cur.convRate, prev.convRate)),
    "Order value": fmtVar1(varPct(cur.orderValue, prev.orderValue)),
    AOV: fmtVar1(varPct(cur.aov, prev.aov)),
    "Publ Commission": fmtVar1(varPct(cur.pubCommission, prev.pubCommission)),
    "Total Commission": fmtVar1(varPct(cur.totalCommission, prev.totalCommission)),
    CPA: fmtVar1(varPct(cur.cpa, prev.cpa)),
    ROI: fmtVar1(varPct(cur.roi, prev.roi))
  }
];

let programScopeTable = [];

{
  const currentPrograms = aggregateByProgram(currentItems);
  const previousPrograms = aggregateByProgram(previousItems);
  const previousByKey = new Map(previousPrograms.map((row) => [row.key, row]));

  programScopeTable = currentPrograms
    .map((current) => {
      const previous = previousByKey.get(current.key) || {
        programId: current.programId,
        programName: current.programName,
        market: current.market || "-",
        clicks: 0,
        impressions: 0,
        sales: 0,
        orderValue: 0,
        totalCommission: 0
      };

      const currentClicks = current.clicks;
      const currentImpressions = current.impressions;
      const currentSales = current.sales;
      const currentOrderValue = current.orderValue;
      const currentConvRate = currentClicks ? pct(currentSales, currentClicks) : 0;
      const currentAov = currentSales ? (currentOrderValue / currentSales) : 0;
      const ovYoY = varPct(currentOrderValue, previous.orderValue);

      return {
        "Program ID": current.programId,
        Market: current.market || "-",
        Clicks: fmtInt(currentClicks),
        Impressions: fmtInt(currentImpressions),
        Sales: fmtInt(currentSales),
        "Conversion Rate": fmtPct2(currentConvRate),
        AOV: fmtMoney2(currentAov, currencySymbol),
        "Total Order Value": fmtMoney0(currentOrderValue, currencySymbol),
        "YoY Change": fmtVar1(ovYoY),
        _sortCurrentOV: currentOrderValue
      };
    })
    .sort((a, b) => b._sortCurrentOV - a._sortCurrentOV)
    .slice(0, analysisLevel === "organization" ? PROGRAM_TABLE_LIMIT : 25)
    .map((row) => {
      const { _sortCurrentOV, ...cleanRow } = row;
      return cleanRow;
    });
}

const dataForAI = [
  `Reporting period: ${reportingPeriod || "N/A"}`,
  `YoY comparison period: ${comparisonPeriod || "N/A"}`,
  `Analysis level: ${analysisLevel}`,
  `Current filter matched: ${currentFilterMatched}`,
  `Previous filter matched: ${previousFilterMatched}`,
  `Previous baseline available: ${previousBaselineAvailable}`,
  "Program YoY Summary Table (Recent vs Previous)",
  JSON.stringify(rows, null, 2),
  programScopeTable.length ? "Program-level breakdown within organisation scope" : "",
  programScopeTable.length ? JSON.stringify(programScopeTable, null, 2) : ""
].filter(Boolean).join("\n");

return [{
  json: {
    dataForAI,
    programYoYTable: rows,
    programScopeTable,
    currencyCode,
    analysisLevel,
    reportingPeriod,
    comparisonPeriod,
    diagnostics: {
      currentRawRows: allCurrentItems.length,
      previousRawRows: allPreviousItems.length,
      currentFilteredRows: currentItems.length,
      previousFilteredRows: previousItems.length,
      currentFilterMatched,
      previousFilterMatched,
      previousBaselineAvailable
    }
  }
}];

// Process Publisher QBR Pack1 (sales-first, multi-program publisher merge)

const NODE_YOY = 'yoy data extraction1';
const NODE_CUR = 'Collect Publisher Current';
const NODE_PREV = 'Collect Publisher Previous';
const NODE_CAT_CUR = 'Collect Publisher Category Current';
const NODE_CAT_PREV = 'Collect Publisher Category Previous';
const NODE_SOURCE_META = 'Collect Publisher Sources Metadata';

const MINIMUM_PREVIOUS_OV = 2000;
const MIN_SALES_FOR_CPA = 3;
const MAX_ROWS = 10;
const SALE_EVENT_IDS = new Set([422965]);
const LOCALE = 'en-GB';
const SUPPORTED_CURRENCIES = new Set(['GBP', 'EUR', 'USD', 'AUD', 'SEK', 'NOK', 'DKK', 'ISK', 'PLN']);

function normalizeCurrencyCode(code) {
  const c = String(code || '').trim().toUpperCase();
  return SUPPORTED_CURRENCIES.has(c) ? c : '';
}

function getCurrencySymbol(code) {
  switch (String(code || '').toUpperCase()) {
    case 'GBP': return '\u00A3';
    case 'EUR': return '\u20AC';
    case 'USD': return '$';
    case 'AUD': return 'A$';
    case 'PLN': return 'z\u0142';
    case 'SEK':
    case 'NOK':
    case 'DKK':
    case 'ISK': return 'kr';
    default: return '';
  }
}

function safeNum(v) {
  if (v === null || v === undefined || v === '') return 0;
  if (typeof v === 'number') return Number.isFinite(v) ? v : 0;

  let s = String(v).trim().replace(/[^\d,.-]/g, '').replace(/\s+/g, '');
  if (!s) return 0;

  const lastComma = s.lastIndexOf(',');
  const lastDot = s.lastIndexOf('.');

  if (lastComma > -1 && lastDot > -1) {
    if (lastComma > lastDot) {
      s = s.replace(/\./g, '');
      const i = s.lastIndexOf(',');
      s = s.slice(0, i).replace(/,/g, '') + '.' + s.slice(i + 1);
    } else {
      s = s.replace(/,/g, '');
    }
  } else if (lastComma > -1) {
    const decDigits = s.length - lastComma - 1;
    if (decDigits >= 1 && decDigits <= 2) {
      s = s.slice(0, lastComma).replace(/,/g, '') + '.' + s.slice(lastComma + 1);
    } else {
      s = s.replace(/,/g, '');
    }
  } else if (lastDot > -1) {
    const decDigits = s.length - lastDot - 1;
    if (!(decDigits >= 1 && decDigits <= 2)) s = s.replace(/\./g, '');
  }

  const n = Number(s);
  return Number.isFinite(n) ? n : 0;
}

function pickMax(...vals) {
  return vals.reduce((m, v) => Math.max(m, safeNum(v)), 0);
}

function fmtMoney0(amt, sym) {
  const n = Math.round(safeNum(amt));
  const sign = n < 0 ? '-' : '';
  return `${sign}${sym}${Math.abs(n).toLocaleString(LOCALE)}`;
}

function fmtMoney2(amt, sym) {
  const n = safeNum(amt);
  const sign = n < 0 ? '-' : '';
  return `${sign}${sym}${Math.abs(n).toLocaleString(LOCALE, {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  })}`;
}

function fmtInt(num) {
  return Math.round(safeNum(num)).toLocaleString(LOCALE);
}

function fmtYoY(v) {
  if (v === null || v === undefined || !Number.isFinite(v)) return 'N/A';
  return `${v >= 0 ? '+' : ''}${v.toFixed(1)}%`;
}

function toBoolean(v, defaultValue = false) {
  if (v === null || v === undefined || v === '') return defaultValue;
  if (typeof v === 'boolean') return v;
  if (typeof v === 'number') return v !== 0;
  const s = String(v).trim().toLowerCase();
  return s === 'true' || s === '1' || s === 'yes' || s === 'y';
}

function toArray(value) {
  if (Array.isArray(value)) return value;
  if (value === null || value === undefined || value === '') return [];
  return String(value)
    .split(',')
    .map(v => v.trim())
    .filter(Boolean);
}

function normalizePublisherName(name, fallback = 'Unknown Publisher') {
  const cleaned = String(name || '').replace(/\s+/g, ' ').trim();
  return cleaned || fallback;
}

function normKey(name) {
  return normalizePublisherName(name).toLowerCase();
}

function isMetricLikeValue(value) {
  const s = String(value || '').trim();
  if (!s) return false;
  const compact = s.replace(/\s+/g, '');
  return /^[+\-]?\d[\d,.]*%?$/.test(compact) || /^[\u00A3\u20AC$]?[+\-]?\d[\d,.]*%?$/.test(compact);
}

function isPlaceholderPublisher(value) {
  const lower = String(value || '').trim().toLowerCase();
  return !lower || ['unknown', 'unknown publisher', 'n/a', 'na', '-', 'null', 'undefined'].includes(lower);
}

function isValidPublisherLabel(value) {
  if (isPlaceholderPublisher(value)) return false;
  return !isMetricLikeValue(value);
}

function pickPublisherName(item, siteId = '') {
  const candidates = [
    item.sourceName,
    item.source?.name,
    item.publisherName,
    item.publisher?.name,
    item.sourceDisplayName,
    item.publisherDisplayName,
    item.source?.title,
    item.affiliateName,
    item.partnerName,
    item.siteName,
    item.site?.name,
    item.accountName,
  ];

  for (const candidate of candidates) {
    const cleaned = normalizePublisherName(candidate, '');
    if (isValidPublisherLabel(cleaned)) return cleaned;
  }

  if (siteId) return `Publisher ${siteId}`;
  return 'Unknown Publisher';
}

function getItemsFromNodeJson(n) {
  if (!n || typeof n !== 'object') return [];
  if (Array.isArray(n.items)) return n.items;
  if (Array.isArray(n.allItems)) return n.allItems;
  if (Array.isArray(n.rows)) return n.rows;
  if (Array.isArray(n.data)) return n.data;
  return [];
}

function getPublisherKey(item, publisherName) {
  const id = item.sourceId ?? item.publisherId ?? item.siteId ?? item.source?.id;
  if (id !== null && id !== undefined && String(id) !== '') return `id:${id}`;
  return `name:${normKey(publisherName)}`;
}

function isConversionRow(item) {
  const eventName = String(item.eventName || '').toLowerCase();
  const eventId = Number(item.eventId);

  const sales = safeNum(item.sales) + safeNum(item.iSales);
  const ov = pickMax(item.salesOrderValue, item.iSalesOrderValue, item.orderValue, item.eventOrderValue);
  const pubCommission = pickMax(
    item.salesCommission?.publisherCommission,
    item.commission?.publisherCommission,
    item.publisherCommission
  );
  const totalCommission = pickMax(
    item.salesCommission?.totalCommission,
    item.commission?.totalCommission,
    item.commission
  );

  return (
    eventName.includes('sale') ||
    SALE_EVENT_IDS.has(eventId) ||
    sales > 0 ||
    ov > 0 ||
    pubCommission > 0 ||
    totalCommission > 0
  );
}

function aggregateByPublisher(items) {
  const map = new Map();
  let conversionRows = 0;

  for (const item of items || []) {
    const isConversion = isConversionRow(item);
    const hasAnyActivity = isConversion || safeNum(item.clicks) > 0 || safeNum(item.uniqueVisitors) > 0 || safeNum(item.impressions) > 0 || pickMax(item.salesOrderValue, item.iSalesOrderValue, item.orderValue, item.eventOrderValue) > 0 || (safeNum(item.sales) + safeNum(item.iSales)) > 0;
    if (!hasAnyActivity) continue;
    if (isConversion) conversionRows += 1;

    const rawSiteId = item.sourceId ?? item.publisherId ?? item.siteId ?? item.source?.id ?? null;
    const siteId = rawSiteId !== null && rawSiteId !== undefined && String(rawSiteId).trim() !== ''
      ? String(rawSiteId).trim()
      : '';
    const publisher = pickPublisherName(item, siteId);
    const key = getPublisherKey(item, publisher);

    const ov = pickMax(item.salesOrderValue, item.iSalesOrderValue, item.orderValue, item.eventOrderValue);
    const sales = safeNum(item.sales) + safeNum(item.iSales);
    const clicks = safeNum(item.clicks);
    const pubCommission = pickMax(
      item.salesCommission?.publisherCommission,
      item.commission?.publisherCommission,
      item.publisherCommission
    );

    if (!map.has(key)) {
      map.set(key, {
        publisherKey: key,
        publisher,
        siteId,
        ov: 0,
        sales: 0,
        clicks: 0,
        pubCommission: 0,
      });
    }

    const acc = map.get(key);
    if (!acc.siteId && siteId) acc.siteId = siteId;
    if ((!isValidPublisherLabel(acc.publisher) || /^unknown publisher$/i.test(acc.publisher)) && isValidPublisherLabel(publisher)) {
      acc.publisher = publisher;
    }
    acc.ov += ov;
    acc.sales += sales;
    acc.clicks += clicks;
    acc.pubCommission += pubCommission;
  }

  return { rows: Array.from(map.values()), conversionRows };
}

function isTestPublisher(nameRaw) {
  const n = normalizePublisherName(nameRaw);
  const lower = n.toLowerCase();
  return /\btest\s*tradedoubler\b/.test(lower);
}

function inferSegment(nameRaw) {
  const name = String(nameRaw || '').toLowerCase();
  if (/(css|google shopping|comparison|compare|idealo|shoparize|genie shopping)/.test(name)) return 'CSS';
  if (/(which|techradar|trustedreviews|guardian|telegraph|independent|media|content)/.test(name)) return 'Content';
  if (/(voucher|coupon|deal|discount|hotukdeals|vouchercodes)/.test(name)) return 'Voucher';
  if (/(cashback|quidco|topcashback|blue light)/.test(name)) return 'Cashback';
  return 'Other';
}

function uniqueByPublisher(rows) {
  const seen = new Set();
  const out = [];
  for (const r of rows) {
    const siteKey = normalizePublisherName(r.siteId || r['Site ID'] || '', '');
    const nameKey = normKey(r.publisher || r.Publisher || '');
    const k = siteKey ? `id:${siteKey}` : `name:${nameKey}`;
    if (seen.has(k)) continue;
    seen.add(k);
    out.push(r);
  }
  return out;
}

function categoryNameFor(item) {
  return normalizePublisherName(item.categoryName || item.category || item.publisherCategoryName || item.publisherCategory || 'Other', 'Other');
}

function aggregateCategories(items) {
  const map = new Map();
  for (const item of items || []) {
    const category = categoryNameFor(item);
    if (!category) continue;
    if (!map.has(category)) {
      map.set(category, {
        category,
        clicks: 0,
        uniqueVisitors: 0,
        sales: 0,
        orderValue: 0,
        publisherCommission: 0,
        totalCommission: 0
      });
    }

    const acc = map.get(category);
    const commission = item.commission || item.salesCommission || {};
    acc.clicks += safeNum(item.clicks);
    acc.uniqueVisitors += safeNum(item.uniqueVisitors);
    acc.sales += safeNum(item.sales) + safeNum(item.iSales);
    acc.orderValue += pickMax(item.orderValue, item.salesOrderValue, item.iSalesOrderValue);
    acc.publisherCommission += pickMax(commission.publisherCommission, item.salesCommission?.publisherCommission, item.publisherCommission);
    acc.totalCommission += pickMax(commission.totalCommission, item.salesCommission?.totalCommission, item.totalCommission);
  }
  return Array.from(map.values());
}

function buildCategorySegmentSummary(currentCategoryRows, previousCategoryRows) {
  const previousByCategory = new Map((previousCategoryRows || []).map((row) => [row.category.toLowerCase(), row]));

  return (currentCategoryRows || [])
    .filter((row) => row.orderValue > 0 || row.sales > 0 || row.clicks > 0)
    .map((current) => {
      const previous = previousByCategory.get(current.category.toLowerCase()) || { sales: 0, orderValue: 0 };
      return {
        Segment: current.category,
        'Total Sales': fmtInt(current.sales),
        'Sales YoY %': previous.sales > 0 ? fmtYoY(((current.sales - previous.sales) / previous.sales) * 100) : 'N/A',
        'Total OV': fmtMoney0(current.orderValue, currencySymbol),
        'OV YoY %': previous.orderValue > 0 ? fmtYoY(((current.orderValue - previous.orderValue) / previous.orderValue) * 100) : 'N/A'
      };
    })
    .sort((a, b) => safeNum(currentCategoryRows.find((row) => row.category === b.Segment)?.orderValue) - safeNum(currentCategoryRows.find((row) => row.category === a.Segment)?.orderValue));
}


