function readProgramIdFromItem(item) {
  const candidates = [
    item.programId,
    item.program?.id,
    item.advertiserProgramId,
    item.offerId,
    item.campaignId
  ];
  for (const candidate of candidates) {
    const value = String(candidate || '').trim();
    if (value) return value;
  }
  return '';
}

function readProgramNameFromItem(item) {
  const candidates = [
    item.programName,
    item.program?.name,
    item.campaignName,
    item.offerName
  ];
  for (const candidate of candidates) {
    const value = String(candidate || '').trim().toLowerCase();
    if (value) return value;
  }
  return '';
}

function hasProgramSignal(items) {
  return (items || []).some((item) => {
    return Boolean(readProgramIdFromItem(item) || readProgramNameFromItem(item));
  });
}

function matchesSelectedProgram(item) {
  if (selectedProgramIds.size === 0 && selectedProgramNames.size === 0) return true;
  const rowProgramId = readProgramIdFromItem(item);
  const rowProgramName = readProgramNameFromItem(item);
  const idMatch = rowProgramId && selectedProgramIds.has(rowProgramId);
  const nameMatch = rowProgramName && selectedProgramNames.has(rowProgramName);
  return Boolean(idMatch || nameMatch);
}
