const excludeEndedPublishers = toBoolean(payload.excludeEndedPublishers, false);

function isExcludedPublisher(row) {
  const byId = row.siteId && excludePublisherIds.has(String(row.siteId));
  const byName = excludePublisherNames.has(normKey(row.publisher));
  const byInternalTdTest = isTestPublisher(row.publisher);
  const isEnded = (
    (row.siteId && endedPublisherIds.has(String(row.siteId))) ||
    endedPublisherNames.has(normKey(row.publisher))
  );
  return byId || byName || byInternalTdTest || (excludeEndedPublishers && isEnded);
}

