  }
}

function readCandidate(item, key) {
  if (!item || typeof item !== "object") return undefined;
  if (Object.prototype.hasOwnProperty.call(item, key)) return item[key];
  if (item.data && typeof item.data === "object" && Object.prototype.hasOwnProperty.call(item.data, key)) {
    return item.data[key];
  }
  return undefined;
}

function readFirst(item, keys, fallback = undefined) {
  for (const key of keys) {
    const value = readCandidate(item, key);
    if (value !== undefined && value !== null) return value;
  }
  return fallback;
}

function hasMeaningfulText(value) {
  return typeof value === "string" ? value.trim().length > 0 : false;
}

function arrayLikeLength(value) {
  const parsed = parseMaybeJson(value);
  if (Array.isArray(parsed)) return parsed.length;
  if (parsed && typeof parsed === "object" && Array.isArray(parsed.rows)) return parsed.rows.length;
  return 0;
}

function objectLikeSize(value) {
  const parsed = parseMaybeJson(value);
  if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) return 0;
  return Object.keys(parsed).length;
}

