  (analysisLevel === "organization" ? "Organisation " + asText(payload.organizationId, "Unknown") : "") ||
  asText(readFirst(programData, ["programName", "clientName"], "")) ||
  asText(readFirst(publisherData, ["programName", "clientName"], "")) ||
  "Unknown";

const reportingPeriod = asText(payload.reportingPeriod, "Not specified");
const comparisonPeriod = asText(payload.comparisonPeriod, "Not specified");
const qbrFocus = asText(payload.qbrFocus || payload.focusTheme, "General performance review");
const qbrFocusDetail = asText(payload.qbrFocusDetail || payload.focusDetail, "");

const processYoYData = $node["Process YoY Data1"]?.json || {};
const publisherPackData = $node["Process Publisher QBR Pack"]?.json || {};
const publisherPackTables = publisherPackData.publisherPerformanceTables || publisherPackData.publisherQbrPack?.tables || {};

const programOutput = clipText(readFirst(programData, ["programOutput", "output"], "(No program analysis returned)"));
const publisherAnalysis = clipText(readFirst(publisherData, ["publisherAnalysis", "output"], "(No publisher analysis returned)"));
const programYoYTable = firstNonEmptyRows(
  readFirst(programData, ["programYoYTable"], []),
  processYoYData.programYoYTable
);
const programScopeTable = firstNonEmptyRows(
  readFirst(programData, ["programScopeTable"], []),
  processYoYData.programScopeTable
);
const publisherTables = firstNonEmptyTables(
  readFirst(publisherData, ["publisherTables"], {}),
  publisherPackTables
);
if (!Array.isArray(publisherTables.topPublisherPerformance) && Array.isArray(publisherTables.top10ByOV)) {
  publisherTables.topPublisherPerformance = publisherTables.top10ByOV;
}
const programInsights = normalizeList(readFirst(programData, ["programInsights"], []));
const publisherInsights = normalizeList(readFirst(publisherData, ["publisherInsights"], []));
const publisherCategorySlides = normalizeList(
