  { key: "movers_aov", title: "Movers & Shakers - AOV" },
  { key: "segment_performance", title: "Publisher Segment Performance" },
];

const closingSlideBlueprint = [
  { key: "brand_new_publishers", title: "Brand New Publishers" },
  ...(publisherCategorySlides.length ? [{ key: "publisher_expansion_opportunities", title: "Publisher Expansion Opportunities" }] : []),
  { key: "new_emerging_publishers", title: "New & Emerging Publishers" },
  { key: "recommendations", title: "Strategic Recommendations" },
  { key: "risks_dependencies", title: "Risks & Dependencies" },
  { key: "thank_you", title: "Thank You" },
  { key: "questions_next_steps", title: "Questions & Next Steps" },
];

const slideBlueprint = [
  ...coreSlideBlueprint,
  ...closingSlideBlueprint,
].map((slide, index) => ({ slide: index + 1, ...slide }));

const requestedSlidesRaw = payload.n_slides ?? payload.targetSlides ?? payload.target_slides;
const requestedSlidesNum = Number(requestedSlidesRaw);
const requestedTargetSlides = Number.isFinite(requestedSlidesNum) && requestedSlidesNum > 0
  ? Math.floor(requestedSlidesNum)
  : slideBlueprint.length;
const targetSlides = publisherCategorySlides.length
  ? slideBlueprint.length
  : Math.min(requestedTargetSlides, slideBlueprint.length);

const baseAdditionalInstructions = asText(
  payload.presentonAdditionalInstructions ||
  payload.presenton_additional_instructions ||
  payload.gammaAdditionalInstructions ||
  payload.gamma_additional_instructions ||
  ""
);

const presentonAdditionalInstructions = [
  baseAdditionalInstructions,
  "Write all narrative text in " + languageName + ".",
  "Use UK number formatting only: 1,234.56. Use currency symbol before values (e.g. GBP 1,899.64). Use % symbol for rates.",
  "Clearly state reporting period (" + reportingPeriod + ") and YoY comparison period (" + comparisonPeriod + ").",
  qbrFocusDetail
    ? "Primary QBR focus: " + qbrFocus + ". Detail: " + qbrFocusDetail + ". Prioritize only focus-relevant facts."
    : "Primary QBR focus: " + qbrFocus + ". Prioritize only focus-relevant facts.",
  analysisLevel === "organization"
    ? "Program KPI tables represent organisation-level performance. Where a program-level comparison table is provided, use it as a supporting breakdown only."
    : "Program KPI tables represent the selected program only.",
  "CONTEXT MODE: stay data-grounded, include concise implications, and provide recommendations only when directly supported by supplied data. Never invent numbers.",
  publisherCategorySlides.length
    ? "Publisher expansion section: use advertiser/sources as gap-analysis data for unconnected publisher prospects. Keep the deck concise with a single Publisher Expansion Opportunities summary slide. The PPTX service will create an Excel workbook with one sheet per Program ID. Each sheet contains Publisher Type, Publisher Name, Source ID, Description, URL, Acceptance Ratio, Accepted Connections, and Rejected Connections, ranked by Accepted Connections then Acceptance Ratio. Do not include sales/order-value/click totals for these unconnected publishers."
    : "",
  "Slide routing mode: use provided slides_markdown in strict order. Do not reorder, merge, or skip slides."
].filter(Boolean).join("\n");

return [
  {
    json: {
      client,
      deckTitle: "QBR - " + client,
      targetSlides,
      templateSlideCount: slideBlueprint.length,
      slideBlueprint: slideBlueprint.slice(0, targetSlides),
      reportingPeriod,
      comparisonPeriod,
      qbrFocus,
      qbrFocusDetail,
      analysisLevel,
      organizationId: asText(payload.organizationId, ""),
      programId: asText(payload.programId, ""),
      programOutput,
      programYoYTable,
      programScopeTable,
      programScopeTitle: analysisLevel === "organization" ? scopeCopy.title : "",
      programScopeDescription: analysisLevel === "organization" ? scopeCopy.description : "",
      programInsights,
      publisherAnalysis,
      publisherInsights,
      publisherTables,
      publisherCategorySlides,
      publisherRecommendationPack: publisherPackData.publisherRecommendationPack || {},
      languageCode,
      languageName,
      currencyCode: asText(payload.currencyCode, "EUR"),
      presentonTemplateId: asText(
        payload.presentonTemplateId ||
        payload.presenton_template_id ||
        payload.templateId ||
        payload.template_id ||
        payload.gammaThemeId ||
        payload.gamma_theme_id ||
        ""
      ),
      presentonAdditionalInstructions,
      presentonExportAs: asText(
        payload.presentonExportAs ||
        payload.presenton_export_as ||
        payload.gammaExportAs ||
        payload.gamma_export_as ||
        "pptx"
      ),
      presentonApiUrl: asText(payload.presentonApiUrl || payload.presenton_api_url || "")
    }
  }
];

